const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);
```

---

### 🟠 Medium Severity

---

#### 3. **Missing Security Headers (OWASP A05: Security Misconfiguration)**

Express sets no security-relevant HTTP headers by default. This leaves the app exposed to clickjacking, MIME-sniffing, and other browser-level attacks.

```js
// ✅ Use helmet to set secure headers
const helmet = require('helmet');
app.use(helmet());
// Sets: X-Content-Type-Options, X-Frame-Options, Strict-Transport-Security,
//       Content-Security-Policy, X-XSS-Protection, and more
```

---

#### 4. **No Body Parser / Input Validation (OWASP A03: Injection)**

The app has no `express.json()` middleware. If POST/PUT routes are added later (very likely), the app will either silently ignore request bodies or process raw, unvalidated input — opening the door to injection attacks.

```js
// ✅ Add body parsing + validation from the start
const { body, validationResult } = require('express-validator');

app.use(express.json({ limit: '10kb' })); // also caps payload size

// Example of validated POST route
app.post('/users',
  body('email').isEmail().normalizeEmail(),
  body('name').isString().trim().escape().isLength({ max: 100 }),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) return res.status(400).json({ errors: errors.array() });
    // ... handle valid input
  }
);
```

---

#### 5. **Information Disclosure via `/health` (OWASP A05: Security Misconfiguration)**

The health endpoint exposes a server-side timestamp in ISO format. While low-risk in isolation, it can help attackers fingerprint timing and confirm server availability before an attack. Consider whether this endpoint needs to be publicly accessible at all.

```js
// ✅ Scope it to internal/monitoring networks, or omit the timestamp
app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // don't leak server time
});
```

---

### 🟡 Low Severity / Best Practices

---

#### 6. **Hardcoded Data (OWASP A02 / Maintainability)**

User data is hardcoded directly in the route handler. In a real application this should come from a database with parameterized queries to prevent SQL/NoSQL injection.

```js
// ❌ Hardcoded — doesn't scale and masks injection risks
res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }]);

// ✅ Database query with parameterization (example with pg)
const { rows } = await pool.query('SELECT id, name FROM users WHERE active = $1', [true]);
res.json(rows);
```

---

#### 7. **No HTTPS Enforcement**

The server listens on port 3000 over plain HTTP with no redirect to HTTPS. All data (including auth tokens, if added) will transit in the clear.

```js
// ✅ Redirect HTTP → HTTPS in production
if (process.env.NODE_ENV === 'production') {
  app.use((req, res, next) => {
    if (req.headers['x-forwarded-proto'] !== 'https') {
      return res.redirect(301, `https://${req.headers.host}${req.url}`);
    }
    next();
  });
}
```

---

#### 8. **No Error Handling Middleware (OWASP A05)**

Without a global error handler, unhandled exceptions will leak stack traces and internal details to clients.

```js
// ✅ Add a catch-all error handler as the last middleware
app.use((err, req, res, next) => {
  console.error(err); // log internally
  res.status(500).json({ error: 'Internal Server Error' }); // never leak err.message
});
```

---

#### 9. **`NODE_ENV` Not Set**

Express behaves differently (and less securely) when `NODE_ENV` is not `production` — for example, verbose error output is enabled by default. Set this explicitly:

```bash
NODE_ENV=production node app.js
```

---

### 📋 Prioritized Remediation Checklist

| Priority | Issue | Fix |
|---|---|---|
| 🔴 Critical | Unauthenticated `/users` exposes PII | Add auth middleware + field filtering |
| 🔴 Critical | No rate limiting | Add `express-rate-limit` |
| 🟠 High | No security headers | Add `helmet` |
| 🟠 High | No input validation | Add `express-validator` + `express.json()` |
| 🟡 Medium | Health endpoint leaks timestamp | Return `{ status: 'ok' }` only |
| 🟡 Medium | No HTTPS enforcement | Add redirect + TLS termination |
| 🟡 Medium | No global error handler | Add error middleware |
| 🟡 Low | Hardcoded user data | Use parameterized DB queries |
| 🟡 Low | `NODE_ENV` unset | Set to `production` in deployment |

---

### 🔧 Minimal "Secure Baseline" Patch

Here's how the top of `app.js` should look after addressing the critical items:

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware — must come first
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// ... routes with authentication ...

// Global error handler — must be last
app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});
```

**Required packages to install:**
```bash
npm install helmet express-rate-limit express-validator jsonwebtoken
```

